# # CLEAN VERSION:
class Solution:
    def search(self, nums: list[int], target: int) -> int:
        ''' #> Goal: O(log n) 
        First attempt, using only description of Binary Search.
        How it works:
            - Check the value in the center of the array.
            - If the target value is lower, search the left half of the array. If the target value is higher, search the right half.
            - Continue step 1 and 2 for the new reduced part of the array until the target value is found or until the search area is empty.
            - If the value is found, return the target value index. If the target value is not found, return -1.
        '''
        len_nums:int = len(nums) 
        #returns index of items in center of nums, and picks left (center+1) side if nums is even 
        i:int = (len_nums // 2 + 1) if (len_nums % 2 and len_nums != 1) else (len_nums // 2) 
        
        # when target not found
        if len_nums == 1: 
            return -1 if target != nums[0] else 0
        
        while i < len_nums:
            # fallback when backtracking
            if target < nums[i] and target > nums[i-1]: return -1
            
            # when the target value is higher, search the right half
            if target > nums[i]: i += 1 
            
            # when the target value is lower, search the left half
            elif target < nums[i]: i -= 1 
            
            # when target == nums[i]
            else: return i

